 19	import { getVMSSHSecretName } from '@kubevirt-utils/resources/vm';
 20	import { isEmpty } from '@kubevirt-utils/utils/utils';
 21	import { DescriptionList, HelperText, HelperTextItem, SplitItem } from '@patternfly/react-core';
 22	
 23	import { useDrawerContext } from './hooks/useDrawerContext';
 24	
 25	type AuthorizedSSHKeyProps = {
 26	  authorizedSSHKey: string;
 27	  namespace: string;
 28	};
 29	const AuthorizedSSHKey: FC<AuthorizedSSHKeyProps> = ({ authorizedSSHKey, namespace }) => {
 30	  const { t } = useKubevirtTranslation();
 31	  const { createModal } = useModal();
 32	  const { setSSHDetails, setVM, sshDetails, template, vm } = useDrawerContext();
 33	
 34	  const vmAttachedSecretName = useMemo(() => getVMSSHSecretName(vm), [vm]);
 35	  const secretName = authorizedSSHKey || vmAttachedSecretName;
 36	
 37	  const additionalSecretResource: IoK8sApiCoreV1Secret = template?.objects?.find(
 38	    (object) => object?.kind === SecretModel.kind,
 39	  );
 40	
 41	  const onSSHChange = useCallback(
 42	    (details: SSHSecretDetails) => {
 43	      const { secretOption, sshPubKey, sshSecretName } = details;
 44	
 45	      if (isEqualObject(details, sshDetails)) {
 46	        return;
 47	      }
 48	
 49	      if (
 50	        secretOption === SecretSelectionOption.none &&
 51	        sshDetails?.secretOption !== SecretSelectionOption.none
 52	      ) {
 53	        setVM(removeSecretToVM(vm));
 54	      }
 55	
 56	      if (
 57	        secretOption === SecretSelectionOption.useExisting &&
 58	        sshDetails?.sshSecretName !== sshSecretName &&
 59	        !isEmpty(sshSecretName)
 60	      ) {
 61	        setVM(addSecretToVM(vm, sshSecretName));
 62	      }
 63	
 64	      if (
 65	        secretOption === SecretSelectionOption.addNew &&
 66	        !isEmpty(sshPubKey) &&
 67	        !isEmpty(sshSecretName)
 68	      ) {
 69	        setVM(addSecretToVM(vm, sshSecretName));
 70	      }
 71	
 72	      setSSHDetails(details);
 73	      return Promise.resolve();
 74	    },
 75	    [sshDetails, setVM, vm, setSSHDetails],
 76	  );
 77	
 78	  useEffect(() => {
 79	    if (isEmpty(sshDetails)) {
 80	      const initialSSHDetails = getInitialSSHDetails({
 81	        applyKeyToProject: !isEmpty(authorizedSSHKey),
 82	        secretToCreate:
 83	          isEmpty(authorizedSSHKey) && !isEmpty(additionalSecretResource)
 84	            ? additionalSecretResource
 85	            : null,
 86	        sshSecretName: secretName,
 87	      });
 88	
 89	      onSSHChange(initialSSHDetails);
 90	    }
 91	  }, [additionalSecretResource, authorizedSSHKey, onSSHChange, secretName, sshDetails]);
 92	
 93	  return (
 94	    <SplitItem>
 95	      <DescriptionList className="pf-v6-c-description-list">
 96	        <VirtualMachineDescriptionItem
 97	          onEditClick={() =>
 98	            createModal((modalProps) => (
 99	              <SSHSecretModal
100	                {...modalProps}
101	                initialSSHSecretDetails={sshDetails}
102	                namespace={namespace}
103	                onSubmit={onSSHChange}
104	              />
105	            ))
106	          }
107	          descriptionData={sshDetails?.sshSecretName || t('Not configured')}
108	          descriptionHeader={t('Public SSH key')}
109	          isEdit
110	        />
111	        {!isEmpty(additionalSecretResource) && (
112	          <HelperText>
113	            <HelperTextItem variant="warning">
114	              {t('This key will override the SSH key secret set on the template')}
115	            </HelperTextItem>
116	          </HelperText>
117	        )}
118	      </DescriptionList>
119	    </SplitItem>
120	  );
121	};
122	
123	export default AuthorizedSSHKey;

